import request from '@/utils/request';

// 获取材质
export function getMaterial(params) {
  return request({
    url: '/product/proCategoryFile/randomList',
    method: 'get',
    params: params
  });
}

// 获取材质
export function getGenerate(params) {
  return request({
    url: '/product/proCategoryCompositeFile/randomList',
    method: 'get',
    params: params
  });
}

// 获取生成次数
export function getUserGenRecordCount() {
  return request({
    url: '/member/memUserGenRecord/count',
    method: 'get'
  });
}

// 获取材质
export function handleAddGenerateRecord(data) {
  return request({
    url: '/member/memUserGenRecord',
    method: 'post',
    data: data
  });
}
// 生成订单
export function handleAddOrder(data) {
  return request({
    url: '/member/memOrder',
    method: 'post',
    data: data
  });
}
